SELECT
            COALESCE(make_date(TRY_CAST(tyear AS INTEGER), (TRY_CAST(regexp_extract(CAST(period AS VARCHAR), '[0-9]+') AS INTEGER) - 1) * 3 + 1, 1), make_date(TRY_CAST(tyear AS INTEGER), 12, 31)) AS "date",
            TRY_CAST(tyear AS INTEGER) AS "year",
            NULLIF(CAST("period" AS VARCHAR), '') AS "period",
            TRY_CAST(NULLIF(CAST("agriculture" AS VARCHAR), '') AS DOUBLE) AS "agriculture",
            TRY_CAST(NULLIF(CAST("cropProduction" AS VARCHAR), '') AS DOUBLE) AS "cropProduction",
            TRY_CAST(NULLIF(CAST("livestock" AS VARCHAR), '') AS DOUBLE) AS "livestock",
