            TRY_CAST(NULLIF(CAST("construction" AS VARCHAR), '') AS DOUBLE) AS "construction",
            TRY_CAST(NULLIF(CAST("services" AS VARCHAR), '') AS DOUBLE) AS "services",
            TRY_CAST(NULLIF(CAST("trade" AS VARCHAR), '') AS DOUBLE) AS "trade",
            TRY_CAST(NULLIF(CAST("accommodationAndFoodServices" AS VARCHAR), '') AS DOUBLE) AS "accommodationAndFoodServices",
